const MAX_KON=5;
const KON_BONUS=[{atk:1.08,agi:1.00,hp:1.00,skill:1.00},{atk:1.08,agi:1.00,hp:1.00,skill:1.00},{atk:1.08,agi:1.00,hp:1.15,skill:1.15},{atk:1.20,agi:1.00,hp:1.15,skill:1.15},{atk:1.20,agi:1.00,hp:1.20,skill:1.20}];
const FRAGMENT_RATE={N:5,R:10,SR:20,SSR:50,UR:100};
const getKon=(id,col)=>Math.min(Math.max((col[id]||0)-1,0),MAX_KON);
const getKonBonus=(id,col)=>KON_BONUS[getKon(id,col)-1]||{atk:1,agi:1,hp:1,skill:1};

// ========== SE / BGM ==========
var _sgAC = null;
function _ac() {
  if(!_sgAC || _sgAC.state==="closed") _sgAC=new (window.AudioContext||window.webkitAudioContext)();
  if(_sgAC.state==="suspended") _sgAC.resume();
  return _sgAC;
}
function SE(type) {
  try {
    var c=_ac(), o=c.createOscillator(), g=c.createGain();
    o.connect(g); g.connect(c.destination);
    var t=c.currentTime;
    if(type==="damage"){
      o.type="sawtooth";
      o.frequency.setValueAtTime(280,t); o.frequency.exponentialRampToValueAtTime(60,t+0.18);
      g.gain.setValueAtTime(0.25,t); g.gain.exponentialRampToValueAtTime(0.001,t+0.2);
      o.start(t); o.stop(t+0.2);
    } else if(type==="heal"){
      o.type="sine";
      o.frequency.setValueAtTime(440,t); o.frequency.exponentialRampToValueAtTime(880,t+0.25);
      g.gain.setValueAtTime(0.18,t); g.gain.exponentialRampToValueAtTime(0.001,t+0.35);
      o.start(t); o.stop(t+0.35);
    } else if(type==="skill"){
      o.type="square";
      o.frequency.setValueAtTime(330,t); o.frequency.exponentialRampToValueAtTime(660,t+0.1); o.frequency.exponentialRampToValueAtTime(440,t+0.2);
      g.gain.setValueAtTime(0.15,t); g.gain.exponentialRampToValueAtTime(0.001,t+0.25);
      o.start(t); o.stop(t+0.25);
    } else if(type==="status"){
      o.type="triangle";
      o.frequency.setValueAtTime(550,t); o.frequency.setValueAtTime(700,t+0.08); o.frequency.setValueAtTime(550,t+0.16);
      g.gain.setValueAtTime(0.15,t); g.gain.exponentialRampToValueAtTime(0.001,t+0.25);
      o.start(t); o.stop(t+0.25);
    } else if(type==="victory"){
      [523,659,784,1047].forEach(function(f,i){
        var o2=c.createOscillator(),g2=c.createGain();
        o2.connect(g2); g2.connect(c.destination);
        o2.type="sine"; o2.frequency.value=f;
        g2.gain.setValueAtTime(0,t+i*0.12); g2.gain.linearRampToValueAtTime(0.2,t+i*0.12+0.05);
        g2.gain.exponentialRampToValueAtTime(0.001,t+i*0.12+0.3);
        o2.start(t+i*0.12); o2.stop(t+i*0.12+0.4);
      });
    } else if(type==="defeat"){
      o.type="sawtooth";
      o.frequency.setValueAtTime(400,t); o.frequency.exponentialRampToValueAtTime(80,t+0.6);
      g.gain.setValueAtTime(0.2,t); g.gain.exponentialRampToValueAtTime(0.001,t+0.7);
      o.start(t); o.stop(t+0.7);
    } else if(type==="gacha"){
      [330,440,550,660,880].forEach(function(f,i){
        var o2=c.createOscillator(),g2=c.createGain();
        o2.connect(g2); g2.connect(c.destination);
        o2.type="sine"; o2.frequency.value=f;
        g2.gain.setValueAtTime(0,t+i*0.07); g2.gain.linearRampToValueAtTime(0.18,t+i*0.07+0.03);
        g2.gain.exponentialRampToValueAtTime(0.001,t+i*0.07+0.2);
        o2.start(t+i*0.07); o2.stop(t+i*0.07+0.25);
      });
    }
  } catch(e) {}
}
var _bgmNodes=[];
var _bgmOn=false;
function BGM_START() {
  if(_bgmOn) return;
  _bgmOn=true;
  try {
    var c=_ac();
    var scale=[261,294,330,349,392,440,494,523];
    var melody=[0,2,4,7,4,2,0,4,2,0,4,7,9,7,4,2];
    var bass  =[0,0,7,7,5,5,4,4];
    var bpm=92, step=60/bpm/2;
    function note(freq,start,dur,vol,type){
      var o=c.createOscillator(),g=c.createGain();
      o.connect(g); g.connect(c.destination);
      o.type=type||"sine"; o.frequency.value=freq;
      g.gain.setValueAtTime(0,start);
      g.gain.linearRampToValueAtTime(vol,start+0.02);
      g.gain.exponentialRampToValueAtTime(0.001,start+dur*0.9);
      o.start(start); o.stop(start+dur);
      _bgmNodes.push(o);
    }
    var t=c.currentTime+0.1;
    var loopLen=melody.length*step;
    for(var rep=0;rep<8;rep++){
      melody.forEach(function(si,i){
        var freq=scale[si%8]*(si>=8?2:1);
        note(freq, t+rep*loopLen+i*step, step*0.7, 0.08, "triangle");
      });
      bass.forEach(function(si,i){
        var freq=scale[si%8]/2;
        note(freq, t+rep*loopLen+i*step*2, step*1.8, 0.12, "sine");
      });
    }
  } catch(e) {}
}
function BGM_STOP() {
  _bgmOn=false;
  _bgmNodes.forEach(function(n){try{n.stop();}catch(e){}});
  _bgmNodes=[];
}

