<span style={{fontSize:7,color:sk.kind==="heal"?"rgba(126,201,143,.9)":"rgba(111,179,201,.9)",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",textShadow:"0 1px 4px rgba(0,0,0,1)",flex:1}}>{sk.name}</span>
