function PracticeSetupScreen({onStart,onBack,images,collection={}}) {
const [activeBoard,setActiveBoard]=useState(1);
const [placed1,setPlaced1]=useState({});
const [placed2,setPlaced2]=useState({});
const [sel,setSel]=useState(null);
const [selCard,setSelCard]=useState(null);
const [costMode,setCostMode]=useState("limited");
const placed = activeBoard===1?placed1:placed2;
const setPlaced = activeBoard===1?setPlaced1:setPlaced2;
const placedIds = useMemo(()=>new Set(Object.values(placed)),[placed]);
const toPlacements = (pl) => Object.entries(pl).map(([key,cardId])=>{
const [r,c]=key.split("-").map(Number),card=CARDS.find(x=>x.id===cardId);
return card?{card,row:r,col:c}:null;
}).filter(Boolean);
const placements1 = useMemo(()=>toPlacements(placed1),[placed1]);
const placements2 = useMemo(()=>toPlacements(placed2),[placed2]);
const curCost = useMemo(()=>Object.values(placed).reduce((s,id)=>s+(RARITY_COST[CARD_RARITY[id]||"N"]||1),0),[placed]);
const canStart = placements1.length>0 && placements2.length>0;
const handleCell=(row,col)=>{
const key=`${row}-${col}`,next={...placed};
if(sel){
const isMove=Object.values(next).includes(sel);
if(!isMove && costMode==="limited"){
const cur=Object.values(next).reduce((s,id)=>s+(RARITY_COST[CARD_RARITY[id]||"N"]||1),0);
const add=RARITY_COST[CARD_RARITY[sel]||"N"]||1;
if(cur+add>COST_LIMIT){setSel(null);return;}
}
Object.keys(next).forEach(k=>{if(next[k]===sel)delete next[k];});
next[key]=sel; setPlaced(next); setSel(null);
} else if(next[key]){ delete next[key]; setPlaced({...next}); }
};
const B=(ex={})=>({padding:"10px 6px",borderRadius:8,border:"1px solid #3c4a6e",background:"#1c2640",color:"#e9e6da",fontSize:12,cursor:"pointer",...ex});
const PB=B({border:"1px solid #d9b35c",background:"linear-gradient(180deg,#b8923f,#8f7331)",color:"#fff8e6",fontWeight:700,fontSize:14});
return (
<div style={{maxWidth:520,margin:"0 auto",padding:"18px 12px 50px",display:"flex",flexDirection:"column",gap:14}}>
<header style={{textAlign:"center"}}>
<p style={{margin:0,fontSize:10,letterSpacing:".35em",color:"#6fb3c9"}}>自分の編成で力を試す</p>
<h1 style={{margin:"4px 0",fontFamily:"serif",fontSize:24,fontWeight:600,color:"#d9b35c"}}>模擬戦</h1>
<p style={{margin:0,fontSize:11,color:"#8b93a8"}}>① 盤面1を編成 → ② 盤面2を編成 → ③ 模擬戦開始</p>
</header>
{/* 盤面切替タブ */}
<div style={{display:"flex",gap:6}}>
<button onClick={()=>setActiveBoard(1)} style={{flex:1,padding:"10px 0",borderRadius:8,border:`1px solid ${activeBoard===1?"#d9b35c":"#2a3550"}`,background:activeBoard===1?"#1c2030":"#0d1018",color:activeBoard===1?"#d9b35c":"#5a6a8e",fontSize:12,cursor:"pointer",fontWeight:700}}>
盤面1 {placements1.length>0?`✓ ${placements1.length}体`:""}
</button>
<button onClick={()=>setActiveBoard(2)} style={{flex:1,padding:"10px 0",borderRadius:8,border:`1px solid ${activeBoard===2?"#88ccff":"#2a3550"}`,background:activeBoard===2?"#0d1a2a":"#0d1018",color:activeBoard===2?"#88ccff":"#5a6a8e",fontSize:12,cursor:"pointer",fontWeight:700}}>
盤面2 {placements2.length>0?`✓ ${placements2.length}体`:""}
</button>
</div>
{/* コストモード切替 */}
<div style={{display:"flex",gap:6,justifyContent:"center"}}>
<button onClick={()=>setCostMode("limited")} style={{padding:"6px 16px",borderRadius:99,border:"1px solid "+(costMode==="limited"?"#d9b35c":"#2a3550"),background:costMode==="limited"?"#1c2030":"#0d1018",color:costMode==="limited"?"#d9b35c":"#5a6a8e",fontSize:11,cursor:"pointer",fontWeight:costMode==="limited"?700:400}}>コスト制限（20）</button>
<button onClick={()=>setCostMode("unlimited")} style={{padding:"6px 16px",borderRadius:99,border:"1px solid "+(costMode==="unlimited"?"#4488ff":"#2a3550"),background:costMode==="unlimited"?"#0d1a2a":"#0d1018",color:costMode==="unlimited"?"#88ccff":"#5a6a8e",fontSize:11,cursor:"pointer",fontWeight:costMode==="unlimited"?700:400}}>コスト無制限</button>
</div>
<div style={{background:"#151d31",border:`1px solid ${activeBoard===1?"#8f7331":"#2a4a6e"}`,borderRadius:10,padding:12}}>
<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
<p style={{margin:0,fontSize:10,color:"#8b93a8"}}>{`編成中：盤面${activeBoard}`}</p>
<span style={{fontSize:11,fontFamily:"monospace",fontWeight:700,color:costMode==="limited"&&curCost>=COST_LIMIT?"#d35064":"#d9b35c"}}>
{costMode==="limited"?`コスト ${curCost} / ${COST_LIMIT}`:`コスト ${curCost}`}
</span>
</div>
{[0,1,2].map(row=>(
<div key={row} style={{display:"grid",gridTemplateColumns:"28px 1fr 1fr 1fr",gap:5,marginBottom:5}}>
<span style={{fontSize:9,color:"#d9b35c",display:"flex",alignItems:"center",justifyContent:"center",writingMode:"vertical-rl",background:"#090d18",borderRadius:4}}>{POS_LABEL[POS[row]]}</span>
{[0,1,2].map(col=>{
const oid=placed[`${row}-${col}`],occ=CARDS.find(c=>c.id===oid)||null;
return(
 <button key={col} onClick={()=>handleCell(row,col)} style={{minHeight:52,border:occ?"1px solid #8f7331":"1px dashed #3c4a6e",borderRadius:6,background:occ?"#1c2640":"transparent",color:"#e9e6da",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:1,padding:"3px",position:"relative",overflow:"hidden"}}>
 {occ&&images[occ.id]&&<img src={images[occ.id]} alt="" style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"contain",opacity:.3}}/>}
 {occ&&<span style={{position:"absolute",top:1,right:1,zIndex:2,fontSize:7,background:"rgba(0,0,0,.75)",color:"#d9b35c",borderRadius:99,padding:"0 4px",fontWeight:700,lineHeight:"11px"}}>{"C"+(RARITY_COST[CARD_RARITY[occ.id]||"N"]||1)}</span>}
 <span style={{position:"relative",zIndex:1,fontSize:10,fontWeight:700}}>{occ?occ.name:<span style={{color:sel?"#6fb3c9":"#3c4a6e",fontSize:9}}>{sel?"配置":"空"}</span>}</span>
 {occ&&<span style={{position:"relative",zIndex:1,fontSize:8,color:"#6fb3c9",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:"100%"}}>{occ[POS[row]+"Skill"]&&occ[POS[row]+"Skill"].name}</span>}
 </button>
);
})}
</div>
))}
<div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:4,marginTop:8}}>
{CARDS_BY_COST.map(card=>{
const isSel=card.id===sel,isPlaced=placedIds.has(card.id);
const isOwned=(collection[card.id]||0)>0;
return(
<button key={card.id} onClick={()=>{if(!isOwned)return;const nid=isSel?null:card.id;setSel(nid);setSelCard(nid?card:null);}} disabled={!isOwned} style={{display:"flex",alignItems:"center",gap:6,padding:"6px 8px",borderRadius:7,border:`1px solid ${isSel?"#d9b35c":"#3c4a6e"}`,background:isSel?"#1c2640":"#0f1624",color:isOwned?"#e9e6da":"#4a5468",cursor:isOwned?"pointer":"default",position:"relative",opacity:!isOwned?0.35:(isPlaced&&!isSel?0.5:1),overflow:"hidden",filter:!isOwned?"grayscale(1)":"none"}}>
 {images[card.id]&&<img src={images[card.id]} alt="" style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"contain",opacity:.2}}/>}
 <span style={{position:"relative",fontSize:10,fontWeight:700,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{card.name}</span>
<span style={{position:"absolute",top:2,right:2,fontSize:7,background:"rgba(0,0,0,.7)",color:"#d9b35c",borderRadius:99,padding:"0 3px",fontWeight:700,lineHeight:"11px"}}>{"C"+(RARITY_COST[CARD_RARITY[card.id]||"N"]||1)}</span>
{!isOwned&&<span style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,zIndex:2}}>🔒</span>}
</button>
);
})}
</div>
</div>
{selCard && (
<div style={{background:"#0f1830",border:"1px solid #d9b35c",borderRadius:10,padding:10}}>
<p style={{margin:"0 0 6px",fontSize:10,color:"#d9b35c"}}>{selCard.name} ── 列で変わるスキル</p>
<div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6}}>
{["front","middle","back"].map(pos=>{
const sk=selCard[pos+"Skill"];
if(!sk)return null;
return(
 <div key={pos} style={{background:"#090d18",borderRadius:7,padding:7}}>
 <p style={{margin:"0 0 3px",fontSize:8,color:"#6fb3c9"}}>{POS_LABEL[pos]}</p>
 <p style={{margin:"0 0 2px",fontSize:10,fontWeight:700}}>{sk.name}</p>
 <p style={{margin:0,fontSize:9,color:"#8b93a8"}}>{skInfo(sk)}</p>
 </div>
);
})}
</div>
</div>
)}
<div style={{display:"flex",gap:8}}>
<button onClick={onBack} style={{position:"fixed",top:10,left:10,zIndex:200,padding:"6px 14px",borderRadius:20,background:"rgba(13,18,37,.88)",border:"1px solid #3c4a6e",color:"#e9e6da",fontSize:13,cursor:"pointer",fontWeight:700}}>{"← 戻る"}</button>
<button style={{...PB,flex:2,opacity:canStart?1:0.4}} onClick={()=>{if(canStart)onStart(placements1,placements2);}} disabled={!canStart}>
{canStart?"⚔️ 模擬戦開始！":"両方の盤面を編成してください"}
</button>
</div>
</div>
);
}
